  values
    -- NAVIGATION
    (v_suite_id, '1.1', 'Navigation', 'Page load',
     'Direct Costs page loads with correct title and toolbar',
     'Full page-load check — title, tabs, toolbar, and table must all render.',
     null,
     E'1. Log in as test1@mail.com\n2. Navigate to /67/direct-costs\n3. Wait for the page to stop loading.',
