     E'1. Note the total amount of any record (e.g. "$1,234.56")\n2. Type "1,234" into the search box.',
     'The row with that amount is shown. Other rows that do not contain "1,234" in vendor/invoice/description/amount are hidden.',
     'MEDIUM', 'scenario', '/67/direct-costs'),

    -- FILTERS
    (v_suite_id, '5.1', 'Filters', 'Status filter',
