     'All filter chips disappear. The full unfiltered list is shown. Row count returns to the total for the project.',
     'MEDIUM', 'scenario', '/67/direct-costs'),

    -- SORTING
    (v_suite_id, '6.1', 'Filters', 'Column sort',
