     'Enabling "Received" adds a Received column. Enabling "Paid" adds a Paid column. Enabling "Description" adds a Description column. Disabling "Vendor" removes the Vendor column from the table.',
     'MEDIUM', 'scenario', '/67/direct-costs'),

    -- PAGINATION
    (v_suite_id, '8.1', 'Filters', 'Pagination',
